PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pr: <http://www.wikidata.org/prop/reference/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?startDate ?endDate WHERE {
  wd:Q37308 p:P552 ?statement .
  ?statement ps:P552 wd:Q347 .
  OPTIONAL {
    ?statement pq:P580 ?startDateQualifier .
    ?startDateQualifier pr:P580 ?startDate
  }
  .
  OPTIONAL {
    ?statement pq:P582 ?endDateQualifier .
    ?endDateQualifier pr:P582 ?endDate
  }
}
